import xml.etree.ElementTree as ET
import urllib.request, urllib.parse
import zipfile, io
root = ET.parse('/ctf-workspace/wfs_caps.xml').getroot()
ns = {'wfs': 'http://www.opengis.net/wfs/2.0'}
feature_types = [ft.find('wfs:Name', ns).text for ft in root.findall('.//wfs:FeatureType', ns) if ft.find('wfs:Name', ns) is not None]
base = 'http://192.168.5.0:8080/geoserver/wfs'
for name in feature_types:
    params = {
        'service':'WFS','version':'2.0.0','request':'GetFeature',
        'typeNames':name,'outputFormat':'SHAPE-ZIP'
    }
    url = base + '?' + urllib.parse.urlencode(params)
    print('Checking', name)
    try:
        data = urllib.request.urlopen(url, timeout=30).read()
    except Exception as e:
        print('  download failed', e)
        continue
    try:
        zf = zipfile.ZipFile(io.BytesIO(data))
    except zipfile.BadZipFile:
        continue
    for item in zf.namelist():
        if item.lower().endswith('.dbf'):
            dbf = zf.read(item)
            lower = dbf.lower()
            if b'flag{' in lower:
                idx = lower.index(b'flag{')
                snippet = dbf[idx:idx+100]
                print('FOUND', name)
                print(snippet)
                raise SystemExit
print('Flag not found in DBF attributes')
